import{_ as t,o,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse(`{"title":"7A. Workplace Delegates Rights","description":"","frontmatter":{"title":"7A. Workplace Delegates Rights","eba":"Children's Services Award 2010","topics":["hours","rosters","employment","consultation","union-matters","delegates","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/consultation-disputes/7A-workplace-delegates-rights.md","filePath":"ebas/childrens-services/consultation-disputes/7A-workplace-delegates-rights.md"}`),i={name:"ebas/childrens-services/consultation-disputes/7A-workplace-delegates-rights.md"};function n(s,e,l,p,c,d){return o(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="_7a-workplace-delegates-rights" tabindex="-1">7A. Workplace Delegates Rights <a class="header-anchor" href="#_7a-workplace-delegates-rights" aria-label="Permalink to &quot;7A. Workplace Delegates Rights&quot;">​</a></h1><p><strong>7A.1</strong> Clause 7A provides for the exercise of the rights of workplace delegates set out in section 350C of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p><p>NOTE: Under section 350C(4) of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>, the employer is taken to have afforded a workplace delegate the rights mentioned in section 350C(3) if the employer has complied with clause 7A.</p><p><strong>7A.2</strong> In clause 7A:</p><p>a. <strong>employer</strong> means the employer of the workplace delegate;</p><p>b. <strong>delegate&#39;s organisation</strong> means the employee organisation in accordance with the rules of which the workplace delegate was appointed or elected; and</p><p>c. <strong>eligible employees</strong> means members and persons eligible to be members of the delegate&#39;s organisation who are employed by the employer in the enterprise.</p><pre><code>**7A.3** Before exercising entitlements under clause 7A, a workplace
delegate must give the employer written notice of their appointment
or election as a workplace delegate. If requested, the workplace
delegate must provide the employer with evidence that would satisfy
a reasonable person of their appointment or election.

**7A.4** An employee who ceases to be a workplace delegate must give
written notice to the employer within 14 days.

7A.5 Right of representation
</code></pre><p>A workplace delegate may represent the industrial interests of eligible employees who wish to be represented by the workplace delegate in matters including:</p><p>a. consultation about major workplace change;</p><p>d. consultation about changes to rosters or hours of work;</p><p>e. resolution of disputes;</p><p>f. disciplinary processes;</p><p>g. enterprise bargaining where the workplace delegate has been appointed as a bargaining representative under section 176 of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a> or is assisting the delegate&#39;s organisation with enterprise bargaining; and</p><p>h. any process or procedure within an award, enterprise agreement or policy of the employer under which eligible employees are entitled to be represented and which concerns their industrial interests.</p><pre><code>7A.6 Entitlement to reasonable communication
</code></pre><p>a. A workplace delegate may communicate with eligible employees for the purpose of representing their industrial interests under clause 7A.5. This includes discussing membership of the delegate&#39;s organisation and representation with eligible employees.</p><p>i. A workplace delegate may communicate with eligible employees during working hours or work breaks, or before or after work.</p><p>7A.7 Entitlement to reasonable access to the workplace and workplace facilities</p><p><strong>(a)</strong> The employer must provide a workplace delegate with access to or use of the following workplace facilities:</p><p>i. a room or area to hold discussions that is fit for purpose, private and accessible by the workplace delegate and eligible employees;</p><p>ii. a physical or electronic noticeboard;</p><p>iii. electronic means of communication ordinarily used in the workplace by the employer to communicate with eligible employees and by eligible employees to communicate with each other, including access to Wi-Fi;</p><p>iv. a lockable filing cabinet or other secure document storage area; and</p><p>v. office facilities and equipment including printers, scanners and photocopiers.</p><pre><code>**(b)** The employer is not required to provide access to or use of
a workplace facility under clause 7A.7(a) if:
</code></pre><p>i. the workplace does not have the facility;</p><p>vi. due to operational requirements, it is impractical to provide access to or use of the facility at the time or in the manner it is sought; or</p><p>vii. the employer does not have access to the facility at the enterprise and is unable to obtain access after taking reasonable steps.</p><pre><code> 7A.8 Entitlement to reasonable access to training
</code></pre><p>Unless the employer is a small business employer, the employer must provide a workplace delegate with access to up to 5 days of paid time during normal working hours for initial training and at least one day each subsequent year, to attend training related to representation of the industrial interests of eligible employees, subject to the following conditions:</p><p>a. In each year commencing 1 July, the employer is not required to provide access to paid time for training to more than one workplace delegate per 50 eligible employees.</p><p>j. The number of eligible employees will be determined on the day a delegate requests paid time to attend training, as the number of eligible employees who are:</p><pre><code>i.  full-time or part-time employees; or

ii. regular casual employees.
</code></pre><p>k. Payment for a day of paid time during normal working hours is payment of the amount the workplace delegate would have been paid for the hours the workplace delegate would have been rostered or required to work on that day if the delegate had not been absent from work to attend the training.</p><p>l. The workplace delegate must give the employer not less than 5 weeks&#39; notice (unless the employer and delegate agree to a shorter period of notice) of the dates, subject matter, the daily start and finish times of the training, and the name of the training provider.</p><p>m. If requested by the employer, the workplace delegate must provide the employer with an outline of the training content.</p><p>n. The employer must advise the workplace delegate not less than 2 weeks from the day on which the training is scheduled to commence, whether the workplace delegate&#39;s access to paid time during normal working hours to attend the training has been approved. Such approval must not be unreasonably withheld.</p><p>o. The workplace delegate must, within 7 days after the day on which the training ends, provide the employer with evidence that would satisfy a reasonable person of their attendance at the training.</p><pre><code>7A.9 Exercise of entitlements under clause 7A
</code></pre><p>a. A workplace delegate&#39;s entitlements under clause 7A are subject to the conditions that the workplace delegate must, when exercising those entitlements:</p><pre><code>i.  comply with their duties and obligations as an employee;

ii. comply with the reasonable policies and procedures of the
    employer, including reasonable codes of conduct and requirements
    in relation to occupational health and safety and acceptable use
    of ICT resources;

iii. not hinder, obstruct or prevent the normal performance of work;
     and

iv. not hinder, obstruct or prevent eligible employees exercising
    their rights to freedom of association.
</code></pre><p>p. Clause 7A does not require the employer to provide a workplace delegate with access to electronic means of communication in a way that provides individual contact details for eligible employees.</p><p>q. Clause 7A does not require an eligible employee to be represented by a workplace delegate without the employee&#39;s agreement.</p><p>NOTE: Under section 350A of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>, the employer must not:</p><p>(a) unreasonably fail or refuse to deal with a workplace delegate; or</p><p>(b) knowingly or recklessly make a false or misleading representation to a workplace delegate; or</p><p>(c) unreasonably hinder, obstruct or prevent the exercise of the rights of a workplace delegate under the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a> or clause 7A.</p><p>Plain language terms: delegate rights, union delegate.</p>`,49)])])}const m=t(i,[["render",n]]);export{g as __pageData,m as default};
